import { createSlice } from "@reduxjs/toolkit";
import { getAboutUser, loginUser, registerUser,googleLogin,toggleLike,addEducation, getAllUsers, getConnectionRequest ,getMyConnectionRequest} from "../../action/authAction";

const initialState = {
  user: undefined,
  isError: false,
  isSuccess: false,
  isLoading: false,
  loggedIn: false,
  message: "",
  isTokenThere: false,
  profileFetched: false,
  connections: [],
  connectionRequests: [],
  all_users:[],
  all_profiles_fetched: false
};

const authSlice = createSlice({
  name: "auth",
  initialState,
  reducers: {
    reset: () => initialState,
    handleLoginUser: (state) => {
      state.message = "hello";
    },
    emptyMessage:(state)=>{
        state.message=""
    },
    setTokenIsThere: (state)=>{
      state.isTokenThere= true
    },
    setTokenIsNotThere: (state)=>{
      state.isTokenThere= false
    }
  },
  extraReducers: (builder) => {
    builder
      .addCase(loginUser.pending, (state) => {
        state.isLoading = true;
        state.message = "Knocking the door....";
      })
      .addCase(loginUser.fulfilled, (state, action) => {
        state.isLoading = false;
        state.isError = false;
        state.isSuccess = true;
        state.loggedIn = true;
        state.message = "login is Successfull";
        state.isError = false;
      })
      .addCase(loginUser.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload?.message || "Login failed";
      })
      .addCase(registerUser.pending, (state) => {
        state.isLoading = true;
        state.message = "Registering you.....";
      })
      .addCase(registerUser.fulfilled, (state, action) => {
        state.isLoading = false;
        state.isError = false;
        state.isSuccess = true;
        state.loggedIn = false;
        state.message = {
            message: "Registration is Successfull, Please login in"
        }
      })
        
      .addCase(registerUser.rejected, (state, action) => {
        state.isLoading = false;
        state.isError = true;
        state.message = action.payload?.message || "Registration failed";
      })
      .addCase(googleLogin.pending, (state) => {
  state.isLoading = true;
})
.addCase(googleLogin.fulfilled, (state, action) => {
  state.isLoading = false;
  state.loggedIn = true;
  state.isError = false;
  state.message = action.payload;
})
.addCase(googleLogin.rejected, (state, action) => {
  state.isLoading = false;
  state.isError = true;
  state.loggedIn = false;
  state.message = action.payload;
})
      .addCase(getAboutUser.fulfilled,(state,action)=>{
        state.isLoading=false;
        state.isError=false;
        state.profileFetched=true;
        state.user= action.payload.profile
        // state.connections = action.payload.connections
        // state.connectionRequests = action.payload.connectionRequests
      })
      .addCase(getAllUsers.fulfilled,(state,action)=>{
        state.isLoading = false;
        state.isError=false;
        state.all_profiles_fetched=true;
        state.all_users = action.payload;
      })
      .addCase(getConnectionRequest.fulfilled,(state, action)=>{
        state.connections=action.payload
      })
      .addCase(getConnectionRequest.rejected,(state, action)=>{
        state.message = action.payload
      })
      .addCase(getMyConnectionRequest.fulfilled, (state, action) => {
    state.connectionRequests = action.payload;
})
.addCase(getMyConnectionRequest.rejected, (state, action) => {
    state.message = action.payload;
})
.addCase(addEducation.fulfilled, (state, action) => {
    state.message = action.payload.message;
})
      

  },

});

export const {reset, emptyMessage , setTokenIsThere,setTokenIsNotThere} =authSlice.actions;

export default authSlice.reducer;


